# feature_flag_rollback.py — disable a feature flag via LaunchDarkly API
import os, requests

LD_API_KEY = os.environ["LAUNCHDARKLY_API_KEY"]
PROJECT = "claude-api"
ENV = "production"

def disable_flag(flag_key: str, reason: str):
    url = f"https://app.launchdarkly.com/api/v2/flags/{PROJECT}/{flag_key}"
    patch = {
        "comment": f"Emergency rollback: {reason}",
        "patch": [
            {"op": "replace", "path": f"/environments/{ENV}/on", "value": False}
        ]
    }
    r = requests.patch(url, json=patch,
                       headers={"Authorization": LD_API_KEY, "Content-Type": "application/json"})
    r.raise_for_status()
    print(f"Flag {flag_key} disabled in {ENV}. Effective in ~30s.")

def get_flag_status(flag_key: str) -> dict:
    url = f"https://app.launchdarkly.com/api/v2/flags/{PROJECT}/{flag_key}"
    r = requests.get(url, headers={"Authorization": LD_API_KEY})
    env_config = r.json()["environments"][ENV]
    return {"on": env_config["on"], "rollout": env_config.get("fallthrough")}

if __name__ == "__main__":
    import sys
    flag_key, reason = sys.argv[1], sys.argv[2]
    print(f"Before: {get_flag_status(flag_key)}")
    disable_flag(flag_key, reason)
    import time; time.sleep(35)
    print(f"After: {get_flag_status(flag_key)}")
